sections.body:
MongoDB supports [multi-document transactions](manual/core/transactions) that let you read and write multiple documents
atomically, even across collections.

To perform a transaction:

- Obtain and start a client session with `client.startSession()`.

- Call `session.withTransaction()` to define the transaction. The
  method takes an async callback function and, optionally, a
  configuration object that defines custom [read and write
  settings](manual/core/transactions) for
  the transaction.

  ```javascript
  session.withTransaction(async () => {
     // ... Run MongoDB operations in this callback
  }, {
      readPreference: "primary",
      readConcern: { level: "local" },
      writeConcern: { w: "majority" },
  })
  ```

- In the transaction callback function, run the MongoDB queries that
  you would like to include in the transaction. Be sure to pass the
  `session` to each query to ensure that it is included in the
  transaction.

  ```javascript
  await accounts.updateOne(
    { name: userSubtractPoints },
    { $inc: { browniePoints: -1 * pointVolume } },
    { session }
  );
  ```

- If the callback encounters an error, call
  `session.abortTransaction()` to stop the transaction. An aborted
  transaction does not modify any data.

  ```javascript
  try {
    // ...
  } catch (err) {
    await session.abortTransaction();
  }
  ```

- When the transaction is complete, call `session.endSession()` to
  end the session and free resources.

  ```javascript
  try {
    // ...
  } finally {
    await session.endSession();
  }
  ```

The following example creates two users, "henry" and "michelle", and
a uses a transaction to move "browniePoints" between those users
atomically:

```javascript
exports = function () {
    const client = context.services.get("mongodb-atlas");

    db = client.db("exampleDatabase");

    accounts = db.collection("accounts");
    browniePointsTrades = db.collection("browniePointsTrades");

    // create user accounts with initial balances
    accounts.insertOne({ name: "henry", browniePoints: 42 });
    accounts.insertOne({ name: "michelle", browniePoints: 144 });

    // trade points between user accounts in a transaction
    tradeBrowniePoints(
      client,
      accounts,
      browniePointsTrades,
      "michelle",
      "henry",
      5
    );

    return "Successfully traded brownie points.";
  };

  async function tradeBrowniePoints(
    client,
    accounts,
    browniePointsTrades,
    userAddPoints,
    userSubtractPoints,
    pointVolume
  ) {
    // Step 1: Start a Client Session
    const session = client.startSession();

    // Step 2: Optional. Define options to use for the transaction
    const transactionOptions = {
      readPreference: "primary",
      readConcern: { level: "local" },
      writeConcern: { w: "majority" },
    };

    // Step 3: Use withTransaction to start a transaction, execute the callback, and commit (or abort on error)
    // Note: The callback for withTransaction MUST be async and/or return a Promise.
    try {
      await session.withTransaction(async () => {
        // Step 4: Execute the queries you would like to include in one atomic transaction
        // Important:: You must pass the session to the operations
        await accounts.updateOne(
          { name: userSubtractPoints },
          { $inc: { browniePoints: -1 * pointVolume } },
          { session }
        );
        await accounts.updateOne(
          { name: userAddPoints },
          { $inc: { browniePoints: pointVolume } },
          { session }
        );
        await browniePointsTrades.insertOne(
          {
            userAddPoints: userAddPoints,
            userSubtractPoints: userSubtractPoints,
            pointVolume: pointVolume,
          },
          { session }
        );
      }, transactionOptions);
    } catch (err) {
      // Step 5: Handle errors with a transaction abort
      await session.abortTransaction();
    } finally {
      // Step 6: End the session when you complete the transaction
      await session.endSession();
    }
  }

```

